const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
return { json: { token, body } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const allowed = ['advisor','sub_agent','mga_principal','admin','supervisor'];
if (allowed.indexOf(row.user_role) === -1) return { json: { _unauthorized: true, status: 403 } };
const b = $('Extract').first().json.body;
const keySalary = parseFloat(b.key_person_salary_cents) || 0;
const revContrib = parseFloat(b.revenue_contribution_cents) || 0;
const yearsToReplace = parseFloat(b.years_to_replace) || 3;
const replacementCost = parseFloat(b.replacement_search_cost_cents) || 0;
const coverage = Math.round((keySalary + revContrib) * yearsToReplace + replacementCost);
return { json: { ok: true, calculator: 'business_key_person', vertical_id: 'insurance', coverage_amount_cents: coverage, inputs: { key_person_salary_cents: keySalary, revenue_contribution_cents: revContrib, years_to_replace: yearsToReplace, replacement_search_cost_cents: replacementCost }, disclaimer: 'This is an educational estimate only. Final recommendation must be reviewed and approved by a licensed advisor.' } };
